        std::fs::write(
            dir.join("lib.rs"),
            "fn helper() {}\nstruct S;\nimpl S {\n    fn m(&self) {\n        helper();\n    }\n}\n",
        )
        .unwrap();

        let maps = map(&dir, None, None, false).unwrap();
        let entries = &maps[0].entries;

        let _s_entry = entries.iter().find(|e| e.name == "S").unwrap();
