        .unwrap();

        let maps = map(&dir, None, None, false).unwrap();
        let fib = &maps[0].entries[0];
        assert_eq!(fib.name, "fib");
        assert!(fib.references.is_empty(), "self-reference is excluded, got {:?}", fib.references);

        std::fs::remove_dir_all(&dir).ok();
    }

